import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Tips & Recommendations","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tips-recommendations.md","filePath":"guide/tips-recommendations.md","lastUpdated":1774775059000}'),n={name:"guide/tips-recommendations.md"};function s(r,e,l,d,c,p){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="tips-recommendations" tabindex="-1">Tips &amp; Recommendations <a class="header-anchor" href="#tips-recommendations" aria-label="Permalink to &quot;Tips &amp; Recommendations&quot;">​</a></h1><p>Tips &amp; Recommendations provides actionable guidance on your biomarkers — what lifestyle changes, foods, and supplements may help, backed by linked PubMed studies.</p><h2 id="philosophy" tabindex="-1">Philosophy <a class="header-anchor" href="#philosophy" aria-label="Permalink to &quot;Philosophy&quot;">​</a></h2><p>Recommendations follow a strict priority order:</p><ol><li><strong>Nature</strong> (best option) — sunlight, cold exposure, grounding, sleep, circadian alignment</li><li><strong>Whole Food</strong> — dietary sources that address the marker naturally</li><li><strong>Tools</strong> — products that support natural interventions (light panels, cold plunge, grounding mat)</li><li><strong>Supplements</strong> (last resort) — specific forms when lifestyle and food aren&#39;t enough</li></ol><p>The guiding principle: if the body makes it, support production rather than supplementing directly.</p><h2 id="where-tips-appear" tabindex="-1">Where Tips Appear <a class="header-anchor" href="#where-tips-appear" aria-label="Permalink to &quot;Where Tips Appear&quot;">​</a></h2><p>Tips show up in three places:</p><ul><li><strong>Detail modal</strong> — open any marker and scroll to &quot;What can help&quot; below the chart</li><li><strong>AI Chat</strong> — when the AI recommends supplementation, a collapsible &quot;What can help&quot; section appears below the response</li><li><strong>Context cards</strong> — lifestyle cards (Sleep, Light, Environment, etc.) show a &quot;Tips&quot; badge linking to relevant guidance</li></ul><h2 id="study-references" tabindex="-1">Study References <a class="header-anchor" href="#study-references" aria-label="Permalink to &quot;Study References&quot;">​</a></h2><p>Every supplement form links to a primary study (typically a systematic review or meta-analysis) on PubMed. Click <strong>(study)</strong> next to any form to read the evidence.</p><p>If you find a better study or spot an error, click <strong>Suggest a better study</strong> at the bottom of any recommendation section. This opens a pre-filled GitHub issue.</p><h2 id="first-time-disclosure" tabindex="-1">First-Time Disclosure <a class="header-anchor" href="#first-time-disclosure" aria-label="Permalink to &quot;First-Time Disclosure&quot;">​</a></h2><p>The first time you view recommendations, a disclosure banner appears explaining that suggestions are informational, not medical advice. Recommendations are hidden until you acknowledge this by clicking <strong>Got it</strong>. This only happens once.</p><h2 id="enabling-disabling" tabindex="-1">Enabling / Disabling <a class="header-anchor" href="#enabling-disabling" aria-label="Permalink to &quot;Enabling / Disabling&quot;">​</a></h2><p>Tips &amp; Recommendations can be toggled on or off in <strong>Settings &gt; Display</strong>. When disabled, no tips, badges, or recommendation sections appear anywhere in the app.</p><h2 id="dna-aware-recommendations" tabindex="-1">DNA-Aware Recommendations <a class="header-anchor" href="#dna-aware-recommendations" aria-label="Permalink to &quot;DNA-Aware Recommendations&quot;">​</a></h2><p>If you have <a href="/docs/guide/dna-import.html">DNA data</a> loaded, recommendations become genetics-aware. A <strong>YOUR GENETICS</strong> section appears above the tiers showing relevant SNP results and how they affect supplement choices — for example, MTHFR variants that suggest methylfolate over folic acid.</p><h2 id="what-s-not-included" tabindex="-1">What&#39;s Not Included <a class="header-anchor" href="#what-s-not-included" aria-label="Permalink to &quot;What&#39;s Not Included&quot;">​</a></h2><ul><li>No dosing recommendations — consult your healthcare provider</li><li>No product images or marketing language</li><li>No tracking of which links you click</li><li>Iron supplements are always marked &quot;only if deficient&quot;</li><li>Compounds the body produces naturally (DHEA, glutathione, melatonin) are flagged or replaced with precursor support</li></ul><h2 id="data-source" tabindex="-1">Data Source <a class="header-anchor" href="#data-source" aria-label="Permalink to &quot;Data Source&quot;">​</a></h2><p>The recommendation catalog is a curated JSON file (<code>data/recommendations-czsk.json</code>) with 80 slots covering biomarkers and lifestyle areas. Each slot includes free actions, food sources, supplement forms, and PubMed references. The catalog is open source and community contributions are welcome.</p>',22)])])}const m=a(n,[["render",s]]);export{u as __pageData,m as default};
